# via mpmath; C = Sum_{p} (p*log(p)-(p-1)*log(p-1))/(p^2-1) with analytic prime-zeta tail
from mpmath import mp, mpf, log, primezeta, zeta, nstr
import sympy
mp.dps = 130
Psplit = 10**5
sp = list(sympy.primerange(2, Psplit+1))
mu = sympy.mobius
C_small = sum((mpf(p)-1)/mpf(p)*(mpf(p)*log(mpf(p))-(mpf(p)-1)*log(mpf(p)-1))/(mpf(p)**2-1) for p in sp)
def Sfull(s):
    o=mp.dps; mp.dps=o+40
    t=mpf(0); n=1
    while True:
        m=mu(n)
        if m: t+=m*(zeta(n*s,derivative=1)/zeta(n*s))
        if mpf(2)**(-n*s)<mpf(10)**(-150): break
        n+=1
    mp.dps=o; return -t
def Ptail(s): return primezeta(s)-sum(mpf(1)/mpf(p)**s for p in sp)
def Stail(s): return Sfull(s)-sum(log(mpf(p))/mpf(p)**s for p in sp)
def L2(s): return mpf(0) if s<3 else -sum(mpf((-1)**(s-m))/m for m in range(1,s-1))
C_tail=mpf(0)
for s in range(2,261):
    a=mpf(1) if s%2==0 else mpf(0); b=mpf(1)/(s-1)+L2(s)
    C_tail+=b*Ptail(s)+(a*Stail(s) if a else mpf(0))
print(nstr(C_small+C_tail,110))

